"use client";

import { useState, useEffect } from "react";
import KakaoMap from "@/components/map/KakaoMap";
import "./pharmacy.css";

// 백엔드 Entity 구조 정의
interface Pharmacy {
  id: number;
  hpid: string;
  dutyName: string;
  dutyTel1: string;
  dutyAddr: string;
  wgs84Lon: string;
  wgs84Lat: string;
  qt: string;
}

export default function PharmacyPage() {
  const [pharmacies, setPharmacies] = useState<Pharmacy[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  
  // 페이징 상태
  const [page, setPage] = useState(0); 
  const [totalPages, setTotalPages] = useState(0);
  const [totalElements, setTotalElements] = useState(0);

  // 데이터 fetch 로직
  const fetchPharmacies = async (pageNum: number) => {
    try {
      setIsLoading(true);
      const response = await fetch(`http://localhost:8080/api/pharmacy/list?page=${pageNum}&size=200`);
      if (!response.ok) throw new Error("Network response was not ok");
      
      const data = await response.json();

      setPharmacies(data.content);
      setTotalPages(data.totalPages);
      setTotalElements(data.totalElements);
    } catch (error) {
      console.error("데이터 로딩 실패:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchPharmacies(page);
  }, [page]);

  return (
    <div className="pharmacy-container">
      <div className="pharmacy-header">
        <h1 className="pharmacy-title">전국 약국 지도 🏥</h1>
        <p className="pharmacy-desc">
          우리 DB에서 관리하는 <strong>{totalElements.toLocaleString()}</strong>개의 약국 정보를 확인하세요.
        </p>
      </div>

      <div className="map-section">
        {/* KakaoMap에 맞는 데이터 구조로 매핑하여 전달 */}
        <KakaoMap 
          pharmacies={pharmacies.map(p => ({
            id: p.hpid,
            place_name: p.dutyName,
            x: p.wgs84Lon,
            y: p.wgs84Lat
          }))} 
        />
      </div>

      <div className="pharmacy-list-section">
        <div className="list-header">
          <h3>검색 결과 <span className="count">{pharmacies.length}</span>건</h3>
          <span className="page-info">({page + 1} / {totalPages} 페이지)</span>
        </div>

        {isLoading ? (
          <div className="loading-msg"><div className="spinner"></div>데이터 로드 중...</div>
        ) : (
          <>
            <div className="pharmacy-grid">
              {pharmacies.map((item) => (
                <div 
                  key={item.hpid} 
                  className="pharmacy-card"
                  onClick={() => window.open(`https://map.kakao.com/link/map/${item.hpid}`, "_blank")}
                >
                  <div className="card-body">
                    <h4 className="place-name">{item.dutyName}</h4>
                    <div className="info-row qt-row">
                      <span className="label">🕒 시간</span>
                      <span className="value qt-value">{item.qt || "정보 없음"}</span>
                    </div>
                    <div className="info-row">
                      <span className="label">주소</span>
                      <span className="value">{item.dutyAddr}</span>
                    </div>
                    <div className="info-row phone-row">
                      <span className="label">전화</span>
                      <span className="value phone">{item.dutyTel1 || "번호 없음"}</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            <div className="pagination">
              <button 
                className="page-btn" 
                onClick={() => setPage(p => Math.max(0, p - 1))} 
                disabled={page === 0}
              >
                이전
              </button>
              <div className="page-numbers">
                <strong>{page + 1}</strong> / {totalPages}
              </div>
              <button 
                className="page-btn" 
                onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))} 
                disabled={page >= totalPages - 1}
              >
                다음
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}